mapper.select:

SELECT CASE 
    WHEN EXISTS (
        SELECT 1 FROM boardMyHomeLikes 
        WHERE boardMyhomeArticleNo = #{boardMyhomeArticleNo} 
          AND memberId = #{memberId}
    ) 
    THEN 'like' 
    ELSE 'noLike' 
END
